/// Create FunctionTemplate for Response.
pub fn create_response_template<'s>(
    scope: &v8::PinScope<'s, '_>,
    parent: Option<v8::Local<'s, v8::FunctionTemplate>>,
) -> v8::Local<'s, v8::FunctionTemplate> {
    let tmpl = v8::FunctionTemplate::builder_raw(empty_constructor).build(scope);
    tmpl.set_class_name(v8::String::new(scope, "Response").unwrap());

    let proto = tmpl.prototype_template(scope);
    {
        let tag_sym = v8::Symbol::get_to_string_tag(scope);
        let tag_val = v8::String::new(scope, "Response").unwrap();
        proto.set(tag_sym.into(), tag_val.into());
    }
    // method: error()
    {
        let name = v8::String::new(scope, "error").unwrap();
        let func_tmpl = v8::FunctionTemplate::builder_raw(response_op_1).build(scope);
        func_tmpl.set_class_name(name);
        proto.set(name.into(), func_tmpl.into());
    }
    // method: redirect()
    {
        let name = v8::String::new(scope, "redirect").unwrap();
        let func_tmpl = v8::FunctionTemplate::builder_raw(response_op_2).build(scope);
        func_tmpl.set_class_name(name);
        proto.set(name.into(), func_tmpl.into());
    }
    // method: json()
    {
        let name = v8::String::new(scope, "json").unwrap();
        let func_tmpl = v8::FunctionTemplate::builder_raw(response_op_3).build(scope);
        func_tmpl.set_class_name(name);
        proto.set(name.into(), func_tmpl.into());
    }
    // attribute: type
    {
        let name = v8::String::new(scope, "type").unwrap();
        let getter = v8::FunctionTemplate::builder_raw(response_get_4).build(scope);
        proto.set_accessor_property(name.into(), Some(getter), None, v8::PropertyAttribute::NONE);
    }
    // attribute: url
    {
        let name = v8::String::new(scope, "url").unwrap();
        let getter = v8::FunctionTemplate::builder_raw(response_get_5).build(scope);
        proto.set_accessor_property(name.into(), Some(getter), None, v8::PropertyAttribute::NONE);
    }
    // attribute: redirected
    {
        let name = v8::String::new(scope, "redirected").unwrap();
        let getter = v8::FunctionTemplate::builder_raw(response_get_6).build(scope);
        proto.set_accessor_property(name.into(), Some(getter), None, v8::PropertyAttribute::NONE);
    }
    // attribute: status
    {
        let name = v8::String::new(scope, "status").unwrap();
        let getter = v8::FunctionTemplate::builder_raw(response_get_7).build(scope);
        proto.set_accessor_property(name.into(), Some(getter), None, v8::PropertyAttribute::NONE);
    }
    // attribute: ok
    {
        let name = v8::String::new(scope, "ok").unwrap();
        let getter = v8::FunctionTemplate::builder_raw(response_get_8).build(scope);
        proto.set_accessor_property(name.into(), Some(getter), None, v8::PropertyAttribute::NONE);
    }
    // attribute: statusText
    {
        let name = v8::String::new(scope, "statusText").unwrap();
        let getter = v8::FunctionTemplate::builder_raw(response_get_9).build(scope);
        proto.set_accessor_property(name.into(), Some(getter), None, v8::PropertyAttribute::NONE);
    }
    // attribute: headers
    {
        let name = v8::String::new(scope, "headers").unwrap();
        let getter = v8::FunctionTemplate::builder_raw(response_get_10).build(scope);
        proto.set_accessor_property(name.into(), Some(getter), None, v8::PropertyAttribute::NONE);
    }
    // method: clone()
    {
        let name = v8::String::new(scope, "clone").unwrap();
        let func_tmpl = v8::FunctionTemplate::builder_raw(response_op_11).build(scope);
        func_tmpl.set_class_name(name);
        proto.set(name.into(), func_tmpl.into());
    }

    tmpl
}

